function FormatTime(time: Time): seq<int>
{
  var total_hours := time.hours + time.days * 24;
  var sign := if time.negative then [45] else [];
  if total_hours < 0 || time.minutes < 0 || time.seconds < 0 then
    []
  else if total_hours > 99 then
    sign + ThreeDigits(total_hours) + [58] + TwoDigits(time.minutes) + [58] + TwoDigits(time.seconds)
  else
    sign + TwoDigits(total_hours) + [58] + TwoDigits(time.minutes) + [58] + TwoDigits(time.seconds)
}
